\caption{	extbf{The procedure of \sysname{}}} \label{whole_algorithm}  egin{algorithmic}[1] \STATE Input: observed source graphs $\{G^i\}_{i=1}^M$, learning rates $l_{in}$, $\l_{out}$ \STATE Select $M$ source graphs as tasks $\{\mathcal{T}^i\}_{i=1}^M$ \STATE Initialize $ oldsymbol{	heta}_t$, $ oldsymbol{	heta}_s$, $ oldsymbol{	heta}_v$, $ oldsymbol{	heta}_d$ and $\{ oldsymbol{	heta}_g^i\}_{i=1}^M$ \STATE While not done do: \STATE \qquad For each task $\mathcal{T}^i$ do: \STATE \qquad \qquad $R_0^i =X^i$ \STATE \qquad \qquad Compute $F^i$ using Eq.~\eqref{eq.edge_weight} \STATE \qquad \qquad Sample $H$ times over $F^i$ to obtain $A'^i$ \STATE \qquad \qquad Compute $R^i$ using Eq.~\eqref{eq.representation} \STATE \qquad \qquad $ oldsymbol{	heta}'^i_{t_{0}} =  oldsymbol{	heta}_t$, $ oldsymbol{	heta}'^i_{s_{0}} =  oldsymbol{	heta}_s$, $ oldsymbol{	heta}'^i_{v_{0}} =  oldsymbol{	heta}_v$, $ oldsymbol{	heta}'^i_{d_{0}} =  oldsymbol{	heta}_d$,$ oldsymbol{	heta}^i_{g_{0}} =  oldsymbol{	heta}_g^i$ \STATE \qquad \qquad Sample $\mathcal{T}_{qry}^{i}$ and $\mathcal{T}_{sup}^{i}$ \STATE \qquad \qquad For n in $1, \dots, \eta$ do: \STATE \qquad \qquad \qquad Compute $\mathcal{L}_{sup}^i$ on $\mathcal{T}_{sup}^{i}$ via Eq.~\eqref{eq.loss_total} \STATE \qquad \qquad \qquad $ oldsymbol{	heta}'^i_{t_{n}} =  oldsymbol{	heta}'^i_{t_{{n-1}}} - l_{in}
abla \mathcal{L}_{sup}^i$ \STATE \qquad \qquad \qquad $ oldsymbol{	heta}'^i_{s_{n}} =  oldsymbol{	heta}'^i_{s_{{n-1}}} - l_{in} 
abla \mathcal{L}_{sup}^i$ \STATE \qquad \qquad \qquad $ oldsymbol{	heta}'^i_{v_{n}} =  oldsymbol{	heta}'^i_{v_{{n-1}}} - l_{in} 
abla \mathcal{L}_{sup}^i$ \STATE \qquad \qquad \qquad $ oldsymbol{	heta}'^i_{d_{n}} =  oldsymbol{	heta}'^i_{d_{{n-1}}} - l_{in} 
abla \mathcal{L}_{sup}^i$ \STATE \qquad \qquad \qquad $ oldsymbol{	heta}_{g_n}^i =  oldsymbol{	heta}^i_{g_{{n-1}}} - l_{in} 
abla \mathcal{L}_{sup}^i$ \STATE \qquad \qquad \qquad Compute $\mathcal{L}_{qry}^{i,n}$ on $\mathcal{T}_{qry}^{i}$ via Eq.~\eqref{eq.loss_total} \STATE \qquad \qquad End \STATE \qquad \qquad $\mathcal{L}_{qry}^{i} = \mathcal{L}_{qry}^{i,\eta}$ \STATE \qquad End \STATE \qquad Update $ oldsymbol{	heta}_t \leftarrow  oldsymbol{	heta}_t - l_{out} 
abla_{ oldsymbol{	heta}_t}  rac{1}{M} \sum_{i=1}^M \mathcal{L}^i_{qry}$ \STATE \qquad Update $ oldsymbol{	heta}_s \leftarrow  oldsymbol{	heta}_s - l_{out} 
abla_{ oldsymbol{	heta}_s}  rac{1}{M} \sum_{i=1}^M \mathcal{L}_{qry}^{i} $ \STATE \qquad Update $ oldsymbol{	heta}_v \leftarrow  oldsymbol{	heta}_v - l_{out} 
abla_{ oldsymbol{	heta}_v}  rac{1}{M} \sum_{i=1}^M \mathcal{L}_{qry}^{i}$ \STATE \qquad Update $ oldsymbol{	heta}_d \leftarrow  oldsymbol{	heta}_d - l_{out} 
abla_{ oldsymbol{	heta}_d}  rac{1}{M} \sum_{i=1}^M \mathcal{L}_{qry}^{i}$ \STATE End while \STATE Output: trained initialization parameters $ oldsymbol{	heta}_t$, $ oldsymbol{	heta}_s$, $ oldsymbol{	heta}_v$ and $ oldsymbol{	heta}_d$ \end{algorithmic}
